local addonName, addonTable = ...
local merfinUI = addonTable.MerfinProfileName
local E = unpack(ElvUI)
local auras = {}
function MUI:ImportWeakAuras(name)
    if not E:IsAddOnEnabled('WeakAuras') then 
        DEFAULT_CHAT_FRAME:AddMessage("|cffbefc03MerfinUI:|r You need to enable WeakAuras first")
        return 
    end
    local name = name
    local importCode = ""
    importCode = auras[name]
    WeakAuras.Import(importCode)
end
